RACE_SVGS = {
    'T': {'viewBox': '0 0 979 958', 'path': TERRAN_SVG},
    'Z': {'viewBox': '0 0 695 763', 'path': ZERG_SVG},
    'P': {'viewBox': '0 0 591 1085', 'path': PROTOSS_SVG},
}


@register.simple_tag
def race_icons_js():
    import json
    return mark_safe(json.dumps(RACE_SVGS))


@register.simple_tag
def race_icon(race, size=24, cls=""):
    race = race.upper() if race else ""
    if race not in RACE_SVGS:
        return ""

    data = RACE_SVGS[race]
    
    # Map code to full name for title/aria-label
    names = {'T': 'Terran', 'Z': 'Zerg', 'P': 'Protoss'}
    name = names.get(race, race)

    # Scale Protoss slightly differently to match visual weight, like in REPLAYMAN
    width = size
    height = size
    if race == 'P':
        width = int(size * 0.85)
        height = int(size * 1.2)

    svg = f"""<svg 
    width="{width}" 
    height="{height}" 
    viewBox="{data['viewBox']}" 
    xmlns="http://www.w3.org/2000/svg"
    fill="currentColor"
    class="race-icon race-{race.lower()} {cls}"
    style="vertical-align: middle;"
    role="img"
    aria-label="{name}"
>
    <title>{name}</title>
    {data['path']}
</svg>"""
    return mark_safe(svg)
